// Script Continued Below
(function executeRule(current, previous /*null when async*/) {

	var grCurrentUserOU = new GlideRecordSecure('x_153465_discovert_discover_office_members');
	grCurrentUserOU.addQuery('office_member', current.office_member);	
	grCurrentUserOU.query();
	// checks if the user is in any other OUs, sets this OU to default if FALSE;
	if(!grCurrentUserOU.hasNext()){
		current.u_isdefaultou = true;
	}

	if(current.u_isdefaultou == true){
		current.u_default_ou = current.getValue('discover_office_hierarchy');
	}
})(current, previous);
